    "sohbetederim": { root: "Sohbet", translation: "drejt / te Bisedë", explanation: "Sohbet (Bisedë) + e (drejt / te) + de (në / tek) + r (zakonisht) + im (unë / jam)\n\nShënim: Bisedë e lirë miqësore (Sohbet etmek)." },
    "sonları": { root: "Son", translation: "Fund / I fundit (shumës)", explanation: "Son (Fund / I fundit) + lar (shumës) + ı ((kallëzore))\n\nShënim: Pika ku mbaron diçka ose elementi i fundit." },
    "sonlarıise": { root: "Son", translation: "Fund / I fundit (shumës)", explanation: "Son (Fund / I fundit) + lar (shumës) + ı ((kallëzore)) + i ((kallëzore)) + se (nëse)\n\nShënim: Pika ku mbaron diçka ose elementi i fundit." },
