    "harfler": { root: "Harf", translation: "Shkronja", explanation: "Harf (Shkronjë) + ler (shumës)\n\nShënim: Shenjë grafike që përfaqëson një tingull." },
    "harflerdir": { root: "Harf", translation: "Shkronja", explanation: "Harf (Shkronjë) + ler (shumës) + dir (është)\n\nShënim: Shenjë grafike që përfaqëson një tingull." },
    "harfleridir": { root: "Harf", translation: "Shkronja", explanation: "Harf (Shkronjë) + ler (shumës) + i ((kallëzore)) + dir (është)\n\nShënim: Shenjë grafike që përfaqëson një tingull." },
    "harfleridirince": { root: "Harf", translation: "Shkronja", explanation: "Harf (Shkronjë) + ler (shumës) + i ((kallëzore)) + dir (është) + ince (kur)\n\nShënim: Shenjë grafike që përfaqëson një tingull." },
    "harflerin": { root: "Harf", translation: "Shkronja", explanation: "Harf (Shkronjë) + ler (shumës) + in (i/e (gjini))\n\nShënim: Shenjë grafike që përfaqëson një tingull." },
