    "buradatam": { root: "Bura", translation: "në / tek Këtu / Kjo pjesë", explanation: "Bura (Këtu / Kjo pjesë) + da (në / tek) + ta (në / tek) + m (imi / ime)\n\nShënim: Tregon një vend afër folësit." },
