    "kutlanacakyeni": { root: "Kutlamak", translation: "do të Festoj / Uroj", explanation: "Kutlamak (Festoj / Uroj) + n (yti / jote) + acak (do të) + ye (drejt / te) + n (yti / jote) + i ((kallëzore))\n\nShënim: Festoj një festë ose uroj dikë." },
    "kuşakaile": { root: "Kuşak", translation: "drejt / te Brez / Gjeneratë", explanation: "Kuşak (Brez / Gjeneratë) + a (drejt / te) + i ((kallëzore)) + le (me)" },
