    "miraslardır": { root: "Miras", translation: "Trashëgimi / Miras (shumës)", explanation: "Miras (Trashëgimi / Miras) + lar (shumës) + dır (është)" },
    "misafirler": { root: "Misafir", translation: "Mysafir / I ftuar (shumës)", explanation: "Misafir (Mysafir / I ftuar) + ler (shumës)\n\nShënim: Vizitor në shtëpi." },
