    "olarak": { root: "Olmak", translation: "Bëhem / Ekzistoj / Ndodh", explanation: "Olmak (Bëhem / Ekzistoj / Ndodh) + arak (duke)\n\nShënim: Folje kryesore ose ndihmëse." },
    "olur": { root: "Olmak", translation: "Bëhem / Ekzistoj / Ndodh", explanation: "Olmak (Bëhem / Ekzistoj / Ndodh) + ur (zakonisht)\n\nShënim: Folje kryesore ose ndihmëse." },
