    "salona": { root: "Salon", translation: "drejt / te Sallë / Sallon", explanation: "Salon (Sallë / Sallon) + a (drejt / te)\n\nShënim: Dhomë e madhe për mysafirë ose për shfaqje e mbledhje." },
    "sağlayacaktır": { root: "Sağlamak", translation: "do të sigurosh / siguroj / mundësoj", explanation: "Sağlamak (Të sigurosh / siguroj / mundësoj) + yacak (do të) + tır (është)\n\nShënim: Mundësimi ose sigurimi i realizimit të diçkaje." },
    "sevgiyi": { root: "Sevgi", translation: "Dashuri", explanation: "Sevgi (Dashuri) + yi ((kallëzore))" },
    "sevgiyle": { root: "Sevgi", translation: "drejt / te Dashuri", explanation: "Sevgi (Dashuri) + yle (me)" },
