    "törenin": { root: "Tören", translation: "Ceremoni / Kremtim", explanation: "Tören (Ceremoni / Kremtim) + in (yti / jote)" },
    "töreninardından": { root: "Tören", translation: "drejt / te Ceremoni / Kremtim", explanation: "Tören (Ceremoni / Kremtim) + in (yti / jote) + a (drejt / te) + r (zakonisht) + d (të shkuar) + ın (i/e (gjini)) + dan (prej / nga)" },
    "töreninin": { root: "Tören", translation: "Ceremoni / Kremtim", explanation: "Tören (Ceremoni / Kremtim) + i ((kallëzore)) + nin (i/e (gjini))" },
