    "yakılır": { root: "Yakmak", translation: "ndezësh / ndez / djeg", explanation: "Yakmak (Të ndezësh / ndez / djeg) + ıl (pësore) + ır (zakonisht)\n\nShënim: Ndezja e zjarrit ose dritës; shkaktimi i djegies." },
    "yapılacağı": { root: "yapılmak", translation: "do të bëhet / realizohet", explanation: "yapılmak (bëhet / realizohet) + acağ (do të) + ı ((kallëzore))\n\nShënim: Forma pasive e foljes \"yapmak\" (bëj)." },
    "yaşanan": { root: "Yaşamak", translation: "Jetoj", explanation: "Yaşamak (Jetoj) + n (yti / jote) + a (drejt / te) + n (yti / jote)" },
    "yaşanananılar": { root: "Yaşamak", translation: "Jetoj", explanation: "Yaşamak (Jetoj) + n (yti / jote) + a (drejt / te) + n (yti / jote) + a (drejt / te) + n (yti / jote) + ı ((kallëzore)) + lar (shumës)" },
    "yaşanır": { root: "Yaşamak", translation: "Jetoj", explanation: "Yaşamak (Jetoj) + n (yti / jote) + ır (zakonisht)" },
