    "yemekleryenir": { root: "Yemek", translation: "drejt / te Ushqim / të hash (shumës)", explanation: "Yemek (Ushqim / të hash) + ler (shumës) + ye (drejt / te) + n (yti / jote) + i ((kallëzore)) + r (zakonisht)" },
    "yenir": { root: "Yemek", translation: "Ushqim / të hash", explanation: "Yemek (Ushqim / të hash) + n (yti / jote) + ir (zakonisht)" },
